PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
SELECT ?pr ?prLabel ?part ?partLabel WHERE {
  ?inst futuram:hasCompositionStatement ?stmt .
  ?stmt futuram:hasPartRelation ?pr .
  ?pr futuram:refersTo ?part .
  OPTIONAL { ?pr rdfs:label ?prLabel }
  OPTIONAL { ?part rdfs:label ?partLabel }
  FILTER(CONTAINS(STR(?inst), "V0501030103"))
}

