arguments.sparql_query:
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX dqv: <http://www.w3.org/ns/dqv#>
SELECT ?whole ?wholeLabel ?y ?m ?u WHERE {
  ?whole a futuram:elvPHEV ;
         rdfs:label ?wholeLabel ;
         futuram:referenceYear ?y ;
         futuram:itemMass [ qudt:numericValue ?m ; qudt:unit ?u ] .
  FILTER(?y = 2020)
}

