PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX crit: <http://purl.org/futuram/criticality#>
PREFIX mw: <https://purl.org/metalwheel#>
PREFIX dqv: <http://www.w3.org/ns/dqv#>
SELECT ?whole ?wholeLabel ?el ?elLabel ?v1 ?u1 ?itemMass ?mUnit ?acc ?com WHERE {
  ?whole a futuram:V0501030103 ; rdfs:label ?wholeLabel ;
         futuram:referenceYear 2020 ;
         futuram:itemMass [ qudt:numericValue ?itemMass ; qudt:unit ?mUnit ] .
  ?whole futuram:hasCompositionStatement ?st1 .
  ?st1 futuram:hasPartRelation ?pr1 .
  ?pr1 futuram:refersTo ?mid ;
       futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?v1 ; qudt:unit ?u1 ] .
  ?mid futuram:hasCompositionStatement ?st2 .
  ?st2 futuram:hasPartRelation ?pr2 .
  ?pr2 futuram:refersTo ?el ;
       futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?v2 ; qudt:unit ?u2 ] .
  ?el rdfs:label ?elLabel .
  ?el rdfs:subClassOf ?chebi . FILTER(CONTAINS(STR(?chebi),"CHEBI"))
  ?chebi crit:remark ?flag .
  ?flag crit:importance ?imp .
  FILTER(?imp = crit:CRITICAL || ?imp = crit:STRATEGIC)
  OPTIONAL {
    ?pr2 dqv:hasQualityMeasurement [ dqv:isMeasurementOf <http://www.w3.org/ns/dqv#accuracy> ; dqv:value ?acc ] .
  }
  OPTIONAL {
    ?pr2 dqv:hasQualityMeasurement [ dqv:isMeasurementOf <http://www.w3.org/ns/dqv#completeness> ; dqv:value ?com ] .
  }
}

