PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl:  <http://www.w3.org/2002/07/owl#>
PREFIX crit: <http://purl.org/futuram/criticality#>
SELECT DISTINCT ?cls ?label ?imp ?year WHERE {
  ?cls a owl:Class .
  ?cls rdfs:subClassOf+ ?chebi . FILTER(CONTAINS(STR(?chebi),"CHEBI"))
  ?chebi crit:remark ?flag .
  ?flag crit:importance ?imp .
  OPTIONAL { ?flag crit:year ?year }
  OPTIONAL { ?cls rdfs:label ?label }
  FILTER(?imp = "CRITICAL"@en)
}
LIMIT 200

