  FILTER( (CONTAINS(LCASE(STR(?label)), "phev") || CONTAINS(LCASE(STR(?comment)), "phev") || CONTAINS(LCASE(STR(?label)), "plug-in") || CONTAINS(LCASE(STR(?comment)), "plug-in")) )
}

