PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX crit: <http://purl.org/futuram/criticality#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT DISTINCT ?elementCls ?elementLabel ?chebi ?importance ?year WHERE {
  ?elementCls rdfs:subClassOf ?chebi .
  FILTER(CONTAINS(STR(?chebi), "CHEBI"))
  ?elementCls a owl:Class .
  ?chebi crit:remark ?flag .
  ?flag crit:importance ?importance .
  OPTIONAL { ?flag crit:year ?year }
  OPTIONAL { ?elementCls rdfs:label ?elementLabel }
}

