  ?ruleset a futuram:UncertaintyRuleset .
  ?ruleset futuram:hasDimensionWeight ?dw .
  ?dw futuram:weightDimension ?dim ; futuram:weightValue ?weight .
  OPTIONAL {
    ?ruleset futuram:hasLimitBand ?lb .
    ?lb futuram:weightedSumLowerBound ?lo ;
         futuram:weightedSumUpperBound ?hi ;
         futuram:bandUncertaintyLimit ?limit .
  }
}

