PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX crit: <http://purl.org/futuram/criticality#>
SELECT DISTINCT ?el ?label WHERE {
  ?el rdfs:subClassOf* <https://www.purl.org/futuram#Element> .
  ?el rdfs:subClassOf ?chebi . FILTER(CONTAINS(STR(?chebi), "CHEBI"))
  ?chebi crit:remark ?flag .
  OPTIONAL { ?el rdfs:label ?label }
} LIMIT 50

